  const [stores, setStores] = useState<Store[]>([]);
  const [requests, setRequests] = useState<TransferRequest[]>([]);
  const [stockTransactions, setStockTransactions] = useState<StockTransaction[]>([]);

  const [voucherItems, setVoucherItems] = useState<{ productId: string, quantity: number }[]>([]);
  const [selectedProductId, setSelectedProductId] = useState('');
  const [selectedQuantity, setSelectedQuantity] = useState(1);

  const [voucherNote, setVoucherNote] = useState('');
  const [targetStoreId, setTargetStoreId] = useState('');
  const [sourceStoreId, setSourceStoreId] = useState('');

  const currentUser = JSON.parse(localStorage.getItem('dialysis_user') || '{}');
  const userPerms = currentUser.permissions || [];

  useEffect(() => { loadData(); }, [activeSubTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [p, s, r, tx] = await Promise.all([
        DB.getProducts(), 
        DB.getStores(), 
        DB.getTransferRequests(),
        DB.getStockTransactions()
      ]);
      setProducts(p || []);
      setStores(s || []);
      setRequests(r || []);
      setStockTransactions(tx || []);
    } catch (err) {
      console.error("Error in Inventory loadData:", err);
    } finally {
      setLoading(false);
    }
  };

  const calculateStock = (productId: string, storeId: string) => {
    let balance = 0;
    stockTransactions.forEach(tx => {
      if (tx.product_id !== productId) return;
      if (tx.type === 'ADD' && tx.store_id === storeId) balance += tx.quantity;
      else if (tx.type === 'DEDUCT' && tx.store_id === storeId) balance -= tx.quantity;
      else if (tx.type === 'TRANSFER') {
        if (tx.store_id === storeId) balance -= tx.quantity;
        if (tx.target_store_id === storeId) balance += tx.quantity;
      }
    });
    return balance;
  };

  const calculateTotalStock = (productId: string) => {
    return visibleStores.reduce((acc, store) => acc + calculateStock(productId, store.id), 0);
  };

  const visibleStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_VIEW:${s.id}`) || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  const manageableStores = stores.filter(s => 
    userPerms.includes('SYSTEM_SETUP') || 
    userPerms.includes('MANAGE_INVENTORY') || 
    userPerms.includes(`STORE_MANAGE:${s.id}`)
  );

  const openModal = (type: 'ADD' | 'DEDUCT' | 'REQUEST') => {
    setMoveType(type);
    setVoucherItems([]);
    setVoucherNote('');
    setTargetStoreId('');
    setSourceStoreId('');
    setShowMoveModal(true);
  };

  const addItemToVoucher = () => {
    if (!selectedProductId || selectedQuantity <= 0) return;
    if (voucherItems.find(i => i.productId === selectedProductId)) return alert("الصنف مضاف بالفعل");
    setVoucherItems([...voucherItems, { productId: selectedProductId, quantity: selectedQuantity }]);
    setSelectedProductId('');
    setSelectedQuantity(1);
  };

  const handleVoucherAction = async (e: React.FormEvent) => {
    e.preventDefault();
    if (voucherItems.length === 0) return alert("يرجى إضافة أصناف أولاً");

    setLoading(true);
    try {
      if (moveType === 'REQUEST') {
        await DB.addTransferRequest({
          from_store_id: sourceStoreId,
          to_store_id: targetStoreId,
          items: voucherItems.map(i => ({ product_id: i.productId, quantity: i.quantity })),
          status: 'PENDING',
          requested_by: currentUser.name,
          note: voucherNote,
          date: new Date().toISOString().split('T')[0]
        });
        alert("تم إرسال طلب التحويل بنجاح");
      } else {
        const storeId = sourceStoreId;
        for (const item of voucherItems) {
          await DB.addStockTransaction({
            product_id: item.productId,
            store_id: storeId,
            type: moveType,
            quantity: item.quantity,
            date: new Date().toISOString().split('T')[0],
            note: voucherNote
          });
        }
        alert("تم تسجيل العملية بنجاح");
      }
      setShowMoveModal(false);
      loadData();
    } catch (err) {
      alert("حدث خطأ أثناء التنفيذ");
    } finally {
      setLoading(false);
    }
  };

  const handleRequestStatus = async (id: string, status: 'APPROVED' | 'REJECTED') => {
    if (!confirm(`هل أنت متأكد من ${status === 'APPROVED' ? 'الموافقة على' : 'رفض'} هذا الطلب؟`)) return;
    setLoading(true);
    try {
      await DB.updateTransferStatus(id, status);
      alert("تم تحديث حالة الطلب بنجاح");
      loadData();
    } catch (err) {
      alert("حدث خطأ");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 no-print">
        <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit">
          <button onClick={() => setActiveSubTab('stock')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'stock' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الأرصدة</button>
          <button onClick={() => setActiveSubTab('requests')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeSubTab === 'requests' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500'}`}>طلبات التحويل ({requests.filter(r => r.status === 'PENDING').length})</button>
        </div>

        <div className="flex gap-2">
           <button onClick={() => openModal('REQUEST')} className="bg-indigo-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md">
             <ArrowLeftRight size={18} /> طلب تحويل
           </button>
           <button onClick={() => openModal('DEDUCT')} className="bg-orange-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md">
             <TrendingDown size={18} /> إذن صـــرف
           </button>
           <button onClick={() => openModal('ADD')} className="bg-green-600 text-white px-5 py-3 rounded-xl text-sm font-bold flex items-center gap-2 shadow-md">
             <TrendingUp size={18} /> توريد
           </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border overflow-hidden min-h-[400px]">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-40 gap-4 text-gray-400">
             <Loader2 className="animate-spin text-primary-600" size={40} />
             <p className="font-bold">جاري التحميل...</p>
          </div>
        ) : activeSubTab === 'stock' ? (
          <div className="p-8">
             <table className="w-full text-right">
                <thead className="bg-gray-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-gray-600 text-xs">الصنف</th>
                    <th className="px-6 py-4 font-bold text-gray-600 text-xs text-center">الإجمالي</th>
                    {visibleStores.map(s => <th key={s.id} className="px-6 py-4 font-bold text-gray-600 text-xs text-center">{s.name}</th>)}
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 font-bold text-gray-700">{p.name} ({p.unit})</td>
                      <td className="px-6 py-4 font-black text-center text-primary-800">{calculateTotalStock(p.id)}</td>
                      {visibleStores.map(s => (
                        <td key={s.id} className="px-6 py-4 font-black text-center text-primary-700">{calculateStock(p.id, s.id)}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
             </table>
          </div>
        ) : (
          <div className="p-8 space-y-4">
             {requests.map(req => (
               <div key={req.id} className="p-6 bg-gray-50 rounded-3xl border flex justify-between items-center group">
                  <div className="flex items-center gap-6">
                     <div className={`p-4 rounded-2xl ${req.status === 'PENDING' ? 'bg-orange-100 text-orange-600' : req.status === 'COMPLETED' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                        {req.status === 'PENDING' ? <Clock size={24}/> : req.status === 'COMPLETED' ? <CheckCircle2 size={24}/> : <Ban size={24}/>}
                     </div>
                     <div>
                        <div className="font-black text-gray-800">طلب تحويل من {stores.find(s => s.id === req.from_store_id)?.name} إلى {stores.find(s => s.id === req.to_store_id)?.name}</div>
                        <div className="text-xs text-gray-400 mt-1 font-bold">بواسطة: {req.requested_by} | التاريخ: {req.date} | الأصناف: {req.items.length}</div>
                     </div>
                  </div>
                  <div className="flex gap-2">
                     {req.status === 'PENDING' && userPerms.includes('MANAGE_INVENTORY') && (
                       <>
                         <button onClick={() => handleRequestStatus(req.id, 'APPROVED')} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-black">موافقة</button>
                         <button onClick={() => handleRequestStatus(req.id, 'REJECTED')} className="bg-red-600 text-white px-4 py-2 rounded-xl text-xs font-black">رفض</button>
                       </>
                     )}
                     <span className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase ${req.status === 'PENDING' ? 'bg-orange-50 text-orange-600' : req.status === 'COMPLETED' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                        {req.status === 'PENDING' ? 'بانتظار الموافقة' : req.status === 'COMPLETED' ? 'تم التحويل' : 'مرفوض'}
                     </span>
                  </div>
               </div>
             ))}
             {requests.length === 0 && <div className="text-center py-20 text-gray-300 italic">لا توجد طلبات تحويل</div>}
          </div>
        )}
      </div>

      {showMoveModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden animate-in zoom-in-95">
            <div className={`p-8 text-white flex justify-between items-center ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'REQUEST' ? 'bg-indigo-600' : 'bg-orange-600'}`}>
              <h3 className="text-2xl font-black">{moveType === 'ADD' ? 'توريد' : moveType === 'REQUEST' ? 'طلب تحويل' : 'صرف'}</h3>
              <button onClick={() => setShowMoveModal(false)}><X size={32}/></button>
            </div>

            <form onSubmit={handleVoucherAction} className="p-10 space-y-8 overflow-y-auto flex-1 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                  <label className="text-xs font-black text-gray-400 mr-2 uppercase">{moveType === 'REQUEST' ? 'المخزن المصدر (المحول منه)' : 'المخزن'}</label>
                  <select value={sourceStoreId} onChange={e => setSourceStoreId(e.target.value)} required className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 font-bold outline-none focus:border-primary-500">
                    <option value="">-- اختر المخزن --</option>
                    {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>

                {moveType === 'REQUEST' && (
                  <div>
                    <label className="text-xs font-black text-gray-400 mr-2 uppercase">مخزن الوجهة (المحول إليه)</label>
                    <select value={targetStoreId} onChange={e => setTargetStoreId(e.target.value)} required className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 font-bold outline-none focus:border-indigo-500">
                      <option value="">-- اختر الوجهة --</option>
                      {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                    </select>
                  </div>
                )}
              </div>

              <div className="bg-primary-50 p-6 rounded-3xl border-2 border-dashed border-primary-100">
                 <div className="grid grid-cols-12 gap-4 items-end">
                    <div className="col-span-12 md:col-span-7">
                       <label className="text-[10px] font-black text-primary-600 uppercase mb-2">الصنف</label>
                       <select value={selectedProductId} onChange={e => setSelectedProductId(e.target.value)} className="w-full border-2 border-white rounded-xl p-3 outline-none">
                         <option value="">-- اختر صنف --</option>
                         {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                       </select>
                    </div>
                    <div className="col-span-8 md:col-span-3">
                       <label className="text-[10px] font-black text-primary-600 uppercase mb-2">الكمية</label>
                       <input type="number" min="1" value={selectedQuantity} onChange={e => setSelectedQuantity(parseInt(e.target.value))} className="w-full border-2 border-white rounded-xl p-3 text-center font-bold outline-none" />
                    </div>
                    <div className="col-span-4 md:col-span-2">
                       <button type="button" onClick={addItemToVoucher} className="w-full py-3 bg-primary-600 text-white rounded-xl font-bold">إضافة</button>
                    </div>
                 </div>
              </div>

              <div className="border-2 border-gray-50 rounded-3xl overflow-hidden">
                 <table className="w-full text-right">
                    <thead className="bg-gray-50">
                       <tr>
                         <th className="px-6 py-3 font-black text-xs text-gray-400">الصنف</th>
                         <th className="px-6 py-3 text-center font-black text-xs text-gray-400">الكمية</th>
                         <th className="px-6 py-3 text-left font-black text-xs text-gray-400">حذف</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                       {voucherItems.map((item, idx) => (
                         <tr key={idx}>
                            <td className="px-6 py-4 font-bold">{products.find(p => p.id === item.productId)?.name}</td>
                            <td className="px-6 py-4 text-center font-black text-primary-600">{item.quantity}</td>
                            <td className="px-6 py-4 text-left">
                               <button type="button" onClick={() => setVoucherItems(voucherItems.filter(v => v.productId !== item.productId))} className="text-red-400 p-2"><Trash2 size={16}/></button>
                            </td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
              </div>

              <textarea placeholder="ملاحظات إضافية..." value={voucherNote} onChange={e => setVoucherNote(e.target.value)} className="w-full border-2 border-gray-100 rounded-2xl p-4 bg-gray-50 h-24 font-bold outline-none"></textarea>

              <div className="flex gap-4">
                <button type="button" onClick={() => setShowMoveModal(false)} className="flex-1 py-5 bg-gray-100 rounded-2xl font-black text-gray-500">إلغاء</button>
                <button type="submit" className={`flex-1 py-5 text-white rounded-2xl font-black shadow-xl ${moveType === 'ADD' ? 'bg-green-600' : moveType === 'REQUEST' ? 'bg-indigo-600' : 'bg-orange-600'}`}>تأكيد العملية</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryModule;

import React, { useState, useEffect } from 'react';
import { AR } from '../constants';
import { DB } from '../store';
import { Service, Store, Product, FinancialAccount, FundingEntity } from '../types';
import { 
  Package, Store as StoreIcon, Tag, Plus, Trash2, X, 
  Loader2, Wallet, Layers, Database, Copy, RefreshCw,
  PlusCircle, Trash, Settings, Edit3, Landmark, Hash, Boxes, Save, CreditCard
} from 'lucide-react';

const SetupModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'services' | 'stores' | 'products' | 'accounts' | 'funding'>('services');
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem] = useState<any>(null);

  const [services, setServices] = useState<Service[]>([]);
  const [stores, setStores] = useState<Store[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [accounts, setAccounts] = useState<FinancialAccount[]>([]);
  const [funding, setFunding] = useState<FundingEntity[]>([]);

  const [customFields, setCustomFields] = useState<string[]>([]);
  const [linkedProducts, setLinkedProducts] = useState<{product_id: string, quantity: number}[]>([]);

  useEffect(() => { loadData(); }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'services') setServices(await DB.getServices());
      if (activeTab === 'stores') setStores(await DB.getStores());
      if (activeTab === 'products') setProducts(await DB.getProducts());
      if (activeTab === 'accounts') setAccounts(await DB.getAccounts());
      if (activeTab === 'funding') setFunding(await DB.getFundingEntities());
    } catch (err: any) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleOpenModal = (item: any = null) => {
    setEditItem(item);
    if (activeTab === 'services') {
      setCustomFields(item?.config?.required_fields || []);
      setLinkedProducts(item?.config?.consumables || []);
    } else {
      setCustomFields([]);
      setLinkedProducts([]);
    }
    setShowModal(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const target = e.target as any;
    setLoading(true);
    try {
      if (activeTab === 'services') {
        const payload = {
          name: target.name.value,
          price: parseFloat(target.price.value),
          category: target.category.value,
          config: { required_fields: customFields, consumables: linkedProducts }
        };
        if (editItem) await DB.updateService(editItem.id, payload);
        else await DB.addService(payload);
      } else if (activeTab === 'stores') {
        const payload = { name: target.name.value, is_main: target.is_main?.checked || false };
        if (editItem) await DB.updateStore(editItem.id, payload);
        else await DB.addStore(payload);
      } else if (activeTab === 'products') {
        const payload = { name: target.name.value, unit: target.unit.value, min_stock: parseFloat(target.min_stock.value), price: parseFloat(target.price.value), category: target.category.value };
        if (editItem) await DB.updateProduct(editItem.id, payload);
        else await DB.addProduct(payload);
      } else if (activeTab === 'accounts') {
        const payload = { name: target.name.value, type: target.type.value, balance: parseFloat(target.balance?.value || editItem.balance) };
        if (editItem) await DB.updateFinancialAccount(editItem.id, payload);
        else await DB.addFinancialAccount(payload);
      } else if (activeTab === 'funding') {
        await DB.addFundingEntity({ name: target.name.value });
      }

      setShowModal(false);
      await loadData();
    } catch (err) { 
      alert("خطأ: " + (err as Error).message); 
    } finally { 
      setLoading(false); 
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex gap-2 p-1 bg-gray-200/50 rounded-xl w-fit flex-wrap">
        <button onClick={() => setActiveTab('services')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'services' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الخدمات</button>
        <button onClick={() => setActiveTab('stores')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'stores' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>المخازن</button>
        <button onClick={() => setActiveTab('products')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'products' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الأصناف</button>
        <button onClick={() => setActiveTab('accounts')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'accounts' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>الحسابات</button>
        <button onClick={() => setActiveTab('funding')} className={`px-6 py-2 rounded-lg font-bold transition-all ${activeTab === 'funding' ? 'bg-white shadow-sm text-primary-600' : 'text-gray-500'}`}>جهات التعاقد</button>
      </div>

      <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border">
        <div className="flex justify-between items-center mb-8">
           <h3 className="text-xl font-black text-gray-800">إدارة الإعدادات والتعريفات</h3>
           <button onClick={() => handleOpenModal()} className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-primary-700 transition-all"><Plus size={20}/> إضافة جديد</button>
        </div>

        {loading ? (
          <div className="flex justify-center py-20"><Loader2 className="animate-spin text-primary-600" size={48} /></div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
             {activeTab === 'services' && services.map(s => (
               <div key={s.id} className="p-6 border rounded-3xl bg-gray-50 hover:bg-white hover:shadow-xl hover:border-primary-200 transition-all group">
                  <div className="flex justify-between items-start mb-4">
                     <div className="p-3 bg-primary-100 text-primary-600 rounded-2xl"><Tag size={20}/></div>
                     <button onClick={() => { if(confirm('حذف الخدمة؟')) DB.deleteService(s.id).then(loadData); }} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={18}/></button>
                  </div>
                  <div className="font-black text-gray-800 text-lg mb-1">{s.name}</div>
                  <div className="text-primary-600 font-bold">{s.price} ج.م</div>
               </div>
             ))}

             {activeTab === 'funding' && funding.map(fe => (
               <div key={fe.id} className="p-6 border rounded-3xl bg-gray-50 hover:bg-white hover:shadow-xl hover:border-emerald-200 transition-all group">
                  <div className="flex justify-between items-start mb-4">
                     <div className="p-3 bg-emerald-100 text-emerald-600 rounded-2xl"><CreditCard size={20}/></div>
                     <button onClick={() => { if(confirm('حذف جهة التعاقد؟')) DB.deleteFundingEntity(fe.id).then(loadData); }} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={18}/></button>
                  </div>
                  <div className="font-black text-gray-800 text-lg mb-1">{fe.name}</div>
                  <div className="text-[10px] text-gray-400 font-bold uppercase mt-2">تاريخ الإضافة: {new Date(fe.created_at).toLocaleDateString()}</div>
               </div>
             ))}

             {activeTab === 'stores' && stores.map(s => (
               <div key={s.id} className="p-6 border rounded-3xl bg-gray-50 hover:bg-white hover:shadow-xl hover:border-indigo-200 transition-all group">
                  <div className="flex justify-between items-start mb-4">
                     <div className="p-3 bg-indigo-100 text-indigo-600 rounded-2xl"><StoreIcon size={20}/></div>
                     <button onClick={() => { if(confirm('حذف المخزن؟')) DB.deleteStore(s.id).then(loadData); }} className="p-2 text-red-400 opacity-0 group-hover:opacity-100"><Trash2 size={18}/></button>
                  </div>
                  <div className="font-black text-gray-800 text-lg mb-1">{s.name}</div>
                  {s.is_main && <span className="text-[10px] bg-amber-100 text-amber-700 px-2 py-1 rounded-full font-bold">المخزن الرئيسي</span>}
               </div>
             ))}

             {/* Products and Accounts logic follows the same pattern as above... */}
          </div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
