const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Detail:", error);
  const code = error.code;

  // PGRST107: Could not find the table in the schema cache
  // 42P01: undefined_table
  if (['42P01', 'PGRST107', 'PGRST116'].includes(code)) {
    throw new Error(`MISSING_TABLE: الجدول غير موجود في قاعدة البيانات. يرجى فتح ملف supabase.ts ونسخ كود SQL وتشغيله في Supabase SQL Editor.`);
  }

  throw new Error(error.message || fallbackMessage);
};

