  // --- Payroll ---
  static async resetShifts() {
    const { error } = await supabase.from('shift_records').delete().neq('id', '00000000-0000-0000-0000-000000000000');
    if (error) return handleError(error, "فشل تصفير الشفتات");
  }

  /** bulkUpdateShifts maps employee codes to IDs and inserts multiple shift records */
  static async bulkUpdateShifts(updates: { employee_code: string; count: number }[]) {
    const { data: employees } = await supabase.from('employees').select('id, code');
    if (!employees) return;

    const records = updates.map(u => {
      const emp = employees.find(e => e.code === u.employee_code);
      if (!emp) return null;
      return {
        employee_id: emp.id,
        count: u.count,
        date: new Date().toISOString().split('T')[0]
      };
    }).filter(Boolean);

    if (records.length > 0) {
      const { error } = await supabase.from('shift_records').insert(records);
      if (error) return handleError(error, "فشل تحديث الشفتات");
    }
  }

