import { 
  Patient, Service, Product, Store, StockTransaction, 
  Employee, FinancialAccount, Transaction, ShiftRecord, User,
  FundingEntity, TransferRequest, LabTest, LabTestDefinition, DialysisSession
} from './types.ts';
import { supabase } from './supabase.ts';

const handleError = (error: any, fallbackMessage: string) => {
  console.error("Database Error Detail:", error);
  const code = error.code;
  if (['42P01', 'PGRST107'].includes(code)) {
    throw new Error(`MISSING_TABLE: الجدول غير موجود. يرجى تشغيل SQL Schema في لوحة تحكم Supabase.`);
  }
  throw new Error(error.message || fallbackMessage);
};

export class DB {
  static async login(username: string, password: string): Promise<User | null> {
    const { data, error } = await supabase.from('system_users').select('*').eq('username', username).eq('password', password).single();
    if (error || !data) return null;
    return data as User;
  }

  // --- Patients ---
  static async addPatient(p: Partial<Patient>) {
    // Phone validation (Must start with 01 and have 11 digits)
    const phoneRegex = /^01\d{9}$/;
    if (p.phone && !phoneRegex.test(p.phone)) {
      throw new Error("رقم الهاتف غير صحيح. يجب أن يبدأ بـ 01 ويتكون من 11 رقم.");
    }

    const { data, error } = await supabase.from('patients').insert([p]).select();
    if (error) return handleError(error, "فشل إضافة المريض");
    return data?.[0];
  }

  static async getPatients() {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) return handleError(error, "فشل جلب المرضى");
    return data || [];
  }

  // --- Inventory & Stock Logic ---
  static async getCurrentStock(productId: string, storeId: string): Promise<number> {
    const { data, error } = await supabase.from('stock_transactions').select('*').eq('product_id', productId);
    if (error) return 0;

    let balance = 0;
    data.forEach((tx: any) => {
      if (tx.type === 'ADD' && tx.store_id === storeId) balance += tx.quantity;
      else if (tx.type === 'DEDUCT' && tx.store_id === storeId) balance -= tx.quantity;
      else if (tx.type === 'TRANSFER') {
        if (tx.store_id === storeId) balance -= tx.quantity;
        if (tx.target_store_id === storeId) balance += tx.quantity;
      }
    });
    return balance;
  }

  static async addStockTransaction(tx: Partial<StockTransaction>) {
    // PREVENT NEGATIVE STOCK
    if (tx.type === 'DEDUCT' || tx.type === 'TRANSFER') {
      const current = await this.getCurrentStock(tx.product_id!, tx.store_id!);
      if (current < tx.quantity!) {
        throw new Error(`عذراً، الرصيد غير كافٍ في هذا المخزن. المتوفر حالياً: ${current}`);
      }
    }

    const { data, error } = await supabase.from('stock_transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل الحركة");
    return data?.[0];
  }

  // --- Transfer Requests & Notifications ---
  static async addTransferRequest(req: Partial<TransferRequest>) {
    const { data, error } = await supabase.from('transfer_requests').insert([req]).select();
    if (error) return handleError(error, "فشل إضافة الطلب");

    await this.addNotification({
      title: "طلب تحويل مخزني جديد",
      message: `تم إنشاء طلب تحويل جديد من مخزن ${req.from_store_id} بواسطة ${req.requested_by}`,
      type: 'info',
      category: 'المخازن'
    });

    return data?.[0];
  }

  static async updateTransferStatus(id: string, status: string) {
    const { data: requestData, error: fetchError } = await supabase.from('transfer_requests').select('*').eq('id', id).single();
    if (fetchError) return handleError(fetchError, "فشل جلب الطلب");

    const { data, error } = await supabase.from('transfer_requests').update({ status }).eq('id', id).select();
    if (error) return handleError(error, "فشل تحديث الحالة");

    const request = data?.[0];
    // Rule: Stock moves only when approved/completed
    if (status === 'COMPLETED' && request) {
      for (const item of request.items) {
        await this.addStockTransaction({
          product_id: item.product_id,
          store_id: request.from_store_id,
          target_store_id: request.to_store_id,
          type: 'TRANSFER',
          quantity: item.quantity,
          date: new Date().toISOString().split('T')[0],
          note: `تحويل آلي - طلب مكتمل #${id}`
        });
      }
    }
    return request;
  }

  // --- Financials ---
  static async addFinanceTx(tx: Partial<Transaction>) {
    const { data, error } = await supabase.from('transactions').insert([tx]).select();
    if (error) return handleError(error, "فشل تسجيل العملية المالية");

    // Update balance immediately
    const { data: acc } = await supabase.from('financial_accounts').select('balance').eq('id', tx.account_id).single();
    if (acc) {
      const newBalance = tx.type === 'INCOME' ? Number(acc.balance) + Number(tx.amount) : Number(acc.balance) - Number(tx.amount);
      await supabase.from('financial_accounts').update({ balance: newBalance }).eq('id', tx.account_id);
    }
    return data?.[0];
  }

  static async resetShifts() {
    const { error } = await supabase.from('shift_records').delete().neq('id', '00000000-0000-0000-0000-000000000000');
    if (error) return handleError(error, "فشل تصفير الدورة المالية");
  }

  // --- Reporting Aggregations ---
  static async getRevenueStats() {
    const { data, error } = await supabase.from('transactions').select('amount, type, date');
    if (error) return [];
    return data;
  }

  // Common CRUDs
  static async getNotifications() { const { data } = await supabase.from('notifications').select('*').order('created_at', { ascending: false }); return data || []; }
  static async addNotification(notif: any) { await supabase.from('notifications').insert([notif]); }
  static async getFundingEntities() { const { data } = await supabase.from('funding_entities').select('*'); return data || []; }
  static async getStores() { const { data } = await supabase.from('stores').select('*'); return data || []; }
  static async getProducts() { const { data } = await supabase.from('products').select('*'); return data || []; }
  static async getStockTransactions() { const { data } = await supabase.from('stock_transactions').select('*'); return data || []; }
  static async getTransferRequests() { const { data } = await supabase.from('transfer_requests').select('*'); return data || []; }
  static async getServices() { const { data } = await supabase.from('services').select('*'); return data || []; }
  static async getSessions() { const { data } = await supabase.from('dialysis_sessions').select('*, patients(*)'); return data || []; }
  static async getEmployees() { const { data } = await supabase.from('employees').select('*'); return data || []; }
  static async getShifts() { const { data } = await supabase.from('shift_records').select('*'); return data || []; }
  static async getAccounts() { const { data } = await supabase.from('financial_accounts').select('*'); return data || []; }
  static async getTransactions() { const { data } = await supabase.from('transactions').select('*'); return data || []; }
  static async getUsers() { const { data } = await supabase.from('system_users').select('*'); return data || []; }
  static async getLabDefinitions() { const { data } = await supabase.from('lab_test_definitions').select('*'); return data || []; }
  static async getLabTests() { const { data } = await supabase.from('lab_tests').select('*, patients(*), lab_test_definitions(*)'); return data || []; }

  // Admin Crud Helpers
  static async addEmployee(e: any) { const { data } = await supabase.from('employees').insert([e]).select(); return data?.[0]; }
  static async updateEmployee(id: string, e: any) { const { data } = await supabase.from('employees').update(e).eq('id', id).select(); return data?.[0]; }
  static async deleteEmployee(id: string) { await supabase.from('employees').delete().eq('id', id); }
  static async addService(s: any) { const { data } = await supabase.from('services').insert([s]).select(); return data?.[0]; }
  static async updateService(id: string, s: any) { const { data } = await supabase.from('services').update(s).eq('id', id).select(); return data?.[0]; }
  static async deleteService(id: string) { await supabase.from('services').delete().eq('id', id); }
  static async addStore(s: any) { const { data } = await supabase.from('stores').insert([s]).select(); return data?.[0]; }
  static async updateStore(id: string, s: any) { const { data } = await supabase.from('stores').update(s).eq('id', id).select(); return data?.[0]; }
  static async deleteStore(id: string) { await supabase.from('stores').delete().eq('id', id); }
  static async addProduct(p: any) { const { data } = await supabase.from('products').insert([p]).select(); return data?.[0]; }
  static async updateProduct(id: string, p: any) { const { data } = await supabase.from('products').update(p).eq('id', id).select(); return data?.[0]; }
  static async addFinancialAccount(a: any) { const { data } = await supabase.from('financial_accounts').insert([a]).select(); return data?.[0]; }
  static async updateFinancialAccount(id: string, a: any) { const { data } = await supabase.from('financial_accounts').update(a).eq('id', id).select(); return data?.[0]; }
  static async addFundingEntity(fe: any) { const { data } = await supabase.from('funding_entities').insert([fe]).select(); return data?.[0]; }
  static async deleteFundingEntity(id: string) { await supabase.from('funding_entities').delete().eq('id', id); }
  static async addUser(u: any) { const { data } = await supabase.from('system_users').insert([u]).select(); return data?.[0]; }
  static async updateUser(id: string, u: any) { const { data } = await supabase.from('system_users').update(u).eq('id', id).select(); return data?.[0]; }
  static async deleteUser(id: string) { await supabase.from('system_users').delete().eq('id', id); }
  static async addLabTest(t: any) { const { data } = await supabase.from('lab_tests').insert([t]).select(); return data?.[0]; }
  static async addLabDefinition(d: any) { const { data } = await supabase.from('lab_test_definitions').insert([d]).select(); return data?.[0]; }
  static async updateLabResult(id: string, res: string) { const { data } = await supabase.from('lab_tests').update({ result: res, status: 'COMPLETED' }).eq('id', id).select(); return data?.[0]; }
  static async addSession(s: any, storeId?: string) { 
    if (storeId && s.service_id) {
      // Auto consume consumables if config exists
      const { data: service } = await supabase.from('services').select('*').eq('id', s.service_id).single();
      if (service?.config?.consumables) {
        for (const item of service.config.consumables) {
           await this.addStockTransaction({
             product_id: item.product_id,
             store_id: storeId,
             type: 'DEDUCT',
             quantity: item.quantity,
             date: new Date().toISOString().split('T')[0],
             note: `استهلاك آلي - جلسة طبية`
           });
        }
      }
    }
    const { data } = await supabase.from('dialysis_sessions').insert([s]).select(); return data?.[0]; 
  }
}

