  const handleResetCycle = async () => {
    if (!confirm('تنبيه هام: هل أنت متأكد من تصفير كافة الشفتات المسجلة لبدء دورة مالية (شهر) جديدة؟ لا يمكن التراجع عن هذا الإجراء.')) return;
