                   </div>
                </div>
             </div>
          </div>
          <table className="w-full text-right">
             <thead className="bg-gray-50/50 border-b">
                <tr>
                   <th className="px-10 py-5 font-black text-xs text-gray-400 uppercase tracking-widest">الموظف</th>
