                    </td>
                    <td className="px-10 py-6">
                       <span className={`px-3 py-1 rounded-lg text-[10px] font-black border ${emp.type === 'PERMANENT' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-amber-50 text-amber-600 border-amber-100'}`}>
